6: import * as assert from 'assert';
7: import { join } from 'path';
8: import * as vscode from 'vscode';
9: import { assertNoRpc, createRandomFile, testFs } from '../utils';
10: 
11: suite('vscode API - languages', () => {
12: 
13: 	teardown(assertNoRpc);
14: 
15: 	const isWindows = process.platform === 'win32';
16: 
17: 	function positionToString(p: vscode.Position) {
18: 		return `[${p.character}/${p.line}]`;
19: 	}
20: 
21: 	function rangeToString(r: vscode.Range) {
22: 		return `[${positionToString(r.start)}/${positionToString(r.end)}]`;
23: 	}
24: 
25: 	function assertEqualRange(actual: vscode.Range, expected: vscode.Range, message?: string) {
26: 		assert.strictEqual(rangeToString(actual), rangeToString(expected), message);
27: 	}
28: 
29: 	test('setTextDocumentLanguage -> close/open event', async function () {
30: 		const file = await createRandomFile('foo\nbar\nbar');
31: 		const doc = await vscode.workspace.openTextDocument(file);
32: 		const langIdNow = doc.languageId;
33: 		let clock = 0;
34: 		const disposables: vscode.Disposable[] = [];
35: 
36: 		const close = new Promise<void>(resolve => {
37: 			disposables.push(vscode.workspace.onDidCloseTextDocument(e => {
38: 				if (e === doc) {
39: 					assert.strictEqual(doc.languageId, langIdNow);
40: 					assert.strictEqual(clock, 0);
41: 					clock += 1;
42: 					resolve();
43: 				}
44: 			}));
45: 		});
46: 		const open = new Promise<void>(resolve => {
47: 			disposables.push(vscode.workspace.onDidOpenTextDocument(e => {
48: 				if (e === doc) { // same instance!
49: 					assert.strictEqual(doc.languageId, 'json');
50: 					assert.strictEqual(clock, 1);
51: 					clock += 1;
52: 					resolve();
53: 				}
54: 			}));
55: 		});
56: 		const change = vscode.languages.setTextDocumentLanguage(doc, 'json');
57: 		await Promise.all([change, close, open]);
58: 		assert.strictEqual(clock, 2);
59: 		assert.strictEqual(doc.languageId, 'json');
60: 		disposables.forEach(disposable => disposable.dispose());
61: 		disposables.length = 0;
62: 	});
63: 
64: 	test('setTextDocumentLanguage -> error when language does not exist', async function () {
65: 		const file = await createRandomFile('foo\nbar\nbar');
66: 		const doc = await vscode.workspace.openTextDocument(file);
67: 
68: 		try {
69: 			await vscode.languages.setTextDocumentLanguage(doc, 'fooLangDoesNotExist');
70: 			assert.ok(false);
71: 		} catch (err) {
72: 			assert.ok(err);
73: 		}
74: 	});
75: 
76: 	test('diagnostics, read & event', function () {
77: 		const uri = vscode.Uri.file('/foo/bar.txt');
78: 		const col1 = vscode.languages.createDiagnosticCollection('foo1');
79: 		col1.set(uri, [new vscode.Diagnostic(new vscode.Range(0, 0, 0, 12), 'error1')]);
80: 
81: 		const col2 = vscode.languages.createDiagnosticCollection('foo2');
82: 		col2.set(uri, [new vscode.Diagnostic(new vscode.Range(0, 0, 0, 12), 'error1')]);
83: 
84: 		const diag = vscode.languages.getDiagnostics(uri);
85: 		assert.strictEqual(diag.length, 2);
86: 
87: 		const tuples = vscode.languages.getDiagnostics();
88: 		let found = false;
89: 		for (const [thisUri,] of tuples) {
90: 			if (thisUri.toString() === uri.toString()) {
91: 				found = true;
92: 				break;
93: 			}
94: 		}
95: 		assert.ok(tuples.length >= 1);
96: 		assert.ok(found);
97: 	});
98: 
99: 	// HINT: If this test fails, and you have been modifying code used in workers, you might have
100: 	// accidentally broken the workers. Check the logs for errors.
101: 	test('link detector', async function () {
102: 		const uri = await createRandomFile('class A { // http://a.com }', undefined, '.java');
103: 		const doc = await vscode.workspace.openTextDocument(uri);
104: 
105: 		const target = vscode.Uri.file(isWindows ? 'c:\\foo\\bar' : '/foo/bar');
106: 		const range = new vscode.Range(new vscode.Position(0, 0), new vscode.Position(0, 5));
107: 
108: 		const linkProvider: vscode.DocumentLinkProvider = {
109: 			provideDocumentLinks: _doc => {
110: 				return [new vscode.DocumentLink(range, target)];
111: 			}
112: 		};
113: 		vscode.languages.registerDocumentLinkProvider({ language: 'java', scheme: testFs.scheme }, linkProvider);
114: 
115: 		const links = await vscode.commands.executeCommand<vscode.DocumentLink[]>('vscode.executeLinkProvider', doc.uri);
116: 		assert.strictEqual(links && links.length, 2, links.map(l => !l.target).join(', '));
117: 		const [link1, link2] = links!.sort((l1, l2) => l1.range.start.compareTo(l2.range.start));
118: 
119: 		assert.strictEqual(link1.target && link1.target.toString(), target.toString());
120: 		assertEqualRange(link1.range, range);
121: 
122: 		assert.strictEqual(link2.target && link2.target.toString(), 'http://a.com/');
123: 		assertEqualRange(link2.range, new vscode.Range(new vscode.Position(0, 13), new vscode.Position(0, 25)));
124: 	});
125: 
126: 	test('diagnostics & CodeActionProvider', async function () {
127: 
128: 		class D2 extends vscode.Diagnostic {
129: 			customProp = { complex() { } };
130: 			constructor() {
131: 				super(new vscode.Range(0, 2, 0, 7), 'sonntag');
132: 			}
133: 		}
134: 
135: 		const diag1 = new vscode.Diagnostic(new vscode.Range(0, 0, 0, 5), 'montag');
136: 		const diag2 = new D2();
137: 
138: 		let ran = false;
139: 		const uri = vscode.Uri.parse('ttt:path.far');
140: 
141: 		const r1 = vscode.languages.registerCodeActionsProvider({ pattern: '*.far', scheme: 'ttt' }, {
142: 			provideCodeActions(_document, _range, ctx): vscode.Command[] {
143: 
144: 				assert.strictEqual(ctx.diagnostics.length, 2);
145: 				const [first, second] = ctx.diagnostics;
146: 				assert.ok(first === diag1);
147: 				assert.ok(second === diag2);
148: 				assert.ok(diag2 instanceof D2);
149: 				ran = true;
150: 				return [];
151: 			}
152: 		});
153: 
154: 		const r2 = vscode.workspace.registerTextDocumentContentProvider('ttt', {
155: 			provideTextDocumentContent() {
156: 				return 'this is some text';
157: 			}
158: 		});
159: 
160: 		const r3 = vscode.languages.createDiagnosticCollection();
161: 		r3.set(uri, [diag1]);
162: 
163: 		const r4 = vscode.languages.createDiagnosticCollection();
164: 		r4.set(uri, [diag2]);
165: 
166: 		await vscode.workspace.openTextDocument(uri);
