22: export class DiagnosticCollection implements vscode.DiagnosticCollection {
23: 
24: 	readonly #proxy: MainThreadDiagnosticsShape | undefined;
25: 	readonly #onDidChangeDiagnostics: Emitter<readonly vscode.Uri[]>;
26: 	readonly #data: ResourceMap<vscode.Diagnostic[]>;
