122: 		// compute change and send to main side
123: 		if (!this.#proxy) {
124: 			return;
125: 		}
126: 		const entries: [URI, IMarkerData[]][] = [];
127: 		let totalMarkerCount = 0;
128: 		for (const uri of toSync) {
129: 			let marker: IMarkerData[] = [];
130: 			const diagnostics = this.#data.get(uri);
131: 			if (diagnostics) {
132: 
133: 				// no more than N diagnostics per file
134: 				if (diagnostics.length > this._maxDiagnosticsPerFile) {
135: 					marker = [];
136: 					const order = [DiagnosticSeverity.Error, DiagnosticSeverity.Warning, DiagnosticSeverity.Information, DiagnosticSeverity.Hint];
137: 					orderLoop: for (let i = 0; i < 4; i++) {
138: 						for (const diagnostic of diagnostics) {
139: 							if (diagnostic.severity === order[i]) {
140: 								const len = marker.push({ ...converter.Diagnostic.from(diagnostic), modelVersionId: this._modelVersionIdProvider(uri) });
141: 								if (len === this._maxDiagnosticsPerFile) {
142: 									break orderLoop;
143: 								}
144: 							}
145: 						}
146: 					}
147: 
148: 					// add 'signal' marker for showing omitted errors/warnings
149: 					marker.push({
150: 						severity: MarkerSeverity.Info,
151: 						message: localize({ key: 'limitHit', comment: ['amount of errors/warning skipped due to limits'] }, "Not showing {0} further errors and warnings.", diagnostics.length - this._maxDiagnosticsPerFile),
152: 						startLineNumber: marker[marker.length - 1].startLineNumber,
153: 						startColumn: marker[marker.length - 1].startColumn,
154: 						endLineNumber: marker[marker.length - 1].endLineNumber,
155: 						endColumn: marker[marker.length - 1].endColumn
156: 					});
157: 				} else {
158: 					marker = diagnostics.map(diag => ({ ...converter.Diagnostic.from(diag), modelVersionId: this._modelVersionIdProvider(uri) }));
159: 				}
160: 			}
161: 
162: 			entries.push([uri, marker]);
163: 
164: 			totalMarkerCount += marker.length;
165: 			if (totalMarkerCount > this._maxDiagnosticsTotal) {
166: 				// ignore markers that are above the limit
167: 				break;
168: 			}
169: 		}
170: 		this.#proxy.$changeMany(this._owner, entries);
171: 	}
